import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'

export default defineConfig({
  plugins: [react()],
  base: process.env.VITE_BASE_PATH || '/',
  server: {
    host: '0.0.0.0',
    cors: true,
    allowedHosts: [
      process.env.__VITE_ADDITIONAL_SERVER_ALLOWED_HOSTS || '.qs.hcllabs.net'
    ],
  },
  build: {
    outDir: 'dist',
    sourcemap: true,
  },
})

/** @type {import('tailwindcss').Config} */
export default {
  content: [
    "./index.html",
    "./src/**/*.{js,ts,jsx,tsx}",
  ],
  theme: {
    extend: {
      colors: {
        'purple-light': '#b794f6',
      },
    },
  },
  plugins: [],
}

export type TimeRange = 'week' | 'month' | 'quarter' | 'year' | 'all';

export interface Department {
  id: string;
  name: string;
}

export interface DataEndpoint {
  id: string;
  name: string;
  url: string;
  enabled: boolean;
}

export interface FilterConfig {
  timeRange: TimeRange;
  department: string; // 'all' or department id
}

export interface DataPoint {
  [key: string]: string | number | boolean | null | undefined;
}

export interface ChartData {
  endpointId: string;
  endpointName: string;
  data: DataPoint[];
  chartType: ChartType;
}

export type ChartType = 'bar' | 'line' | 'pie' | 'area' | 'table';

export interface ChartConfig {
  type: ChartType;
  xAxisKey?: string;
  yAxisKey?: string;
  dataKey?: string;
  nameKey?: string;
}

import React from 'react';
import {
  BarChart,
  Bar,
  LineChart,
  Line,
  PieChart,
  Pie,
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  Cell,
} from 'recharts';
import { ChartData, DataPoint } from '../types';

interface ChartRendererProps {
  chartData: ChartData;
}

const COLORS = ['#3B82F6', '#10B981', '#F59E0B', '#EF4444', '#8B5CF6', '#EC4899', '#06B6D4', '#84CC16'];

const ChartRenderer: React.FC<ChartRendererProps> = ({ chartData }) => {
  const { data, chartType, endpointName } = chartData;

  if (!data || data.length === 0) {
    return (
      <div className="bg-white rounded-lg shadow-md p-6">
        <h3 className="text-lg font-semibold text-gray-800 mb-4">{endpointName}</h3>
        <p className="text-gray-500">No data available</p>
      </div>
    );
  }

  // Determine keys for visualization
  const keys = Object.keys(data[0]);
  const numericKeys = keys.filter((key) => typeof data[0][key] === 'number');
  const stringKeys = keys.filter((key) => typeof data[0][key] === 'string');

  const xKey = stringKeys[0] || keys[0];
  const yKey = numericKeys[0] || keys[1];

  const renderChart = () => {
    switch (chartType) {
      case 'bar':
        return (
          <ResponsiveContainer width="100%" height={350}>
            <BarChart data={data}>
              <CartesianGrid strokeDasharray="3 3" stroke="#e5e7eb" />
              <XAxis dataKey={xKey} stroke="#6b7280" />
              <YAxis stroke="#6b7280" />
              <Tooltip
                contentStyle={{ backgroundColor: '#fff', border: '1px solid #e5e7eb', borderRadius: '6px' }}
              />
              <Legend />
              {numericKeys.map((key, index) => (
                <Bar key={key} dataKey={key} fill={COLORS[index % COLORS.length]} />
              ))}
            </BarChart>
          </ResponsiveContainer>
        );

      case 'line':
        return (
          <ResponsiveContainer width="100%" height={350}>
            <LineChart data={data}>
              <CartesianGrid strokeDasharray="3 3" stroke="#e5e7eb" />
              <XAxis dataKey={xKey} stroke="#6b7280" />
              <YAxis stroke="#6b7280" />
              <Tooltip
                contentStyle={{ backgroundColor: '#fff', border: '1px solid #e5e7eb', borderRadius: '6px' }}
              />
              <Legend />
              {numericKeys.map((key, index) => (
                <Line
                  key={key}
                  type="monotone"
                  dataKey={key}
                  stroke={COLORS[index % COLORS.length]}
                  strokeWidth={2}
                />
              ))}
            </LineChart>
          </ResponsiveContainer>
        );

      case 'area':
        return (
          <ResponsiveContainer width="100%" height={350}>
            <AreaChart data={data}>
              <CartesianGrid strokeDasharray="3 3" stroke="#e5e7eb" />
              <XAxis dataKey={xKey} stroke="#6b7280" />
              <YAxis stroke="#6b7280" />
              <Tooltip
                contentStyle={{ backgroundColor: '#fff', border: '1px solid #e5e7eb', borderRadius: '6px' }}
              />
              <Legend />
              {numericKeys.map((key, index) => (
                <Area
                  key={key}
                  type="monotone"
                  dataKey={key}
                  fill={COLORS[index % COLORS.length]}
                  stroke={COLORS[index % COLORS.length]}
                />
              ))}
            </AreaChart>
          </ResponsiveContainer>
        );

      case 'pie':
        return (
          <ResponsiveContainer width="100%" height={350}>
            <PieChart>
              <Pie
                data={data}
                dataKey={yKey}
                nameKey={xKey}
                cx="50%"
                cy="50%"
                outerRadius={120}
                label
              >
                {data.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                ))}
              </Pie>
              <Tooltip
                contentStyle={{ backgroundColor: '#fff', border: '1px solid #e5e7eb', borderRadius: '6px' }}
              />
              <Legend />
            </PieChart>
          </ResponsiveContainer>
        );

      case 'table':
        return (
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  {keys.map((key) => (
                    <th
                      key={key}
                      className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider"
                    >
                      {key}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {data.map((row, idx) => (
                  <tr key={idx} className="hover:bg-gray-50 transition-colors">
                    {keys.map((key) => (
                      <td key={key} className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                        {String(row[key])}
                      </td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        );

      default:
        return <p className="text-gray-500">Unknown chart type</p>;
    }
  };

  return (
    <div className="bg-white rounded-lg shadow-md p-6 hover:shadow-lg transition-shadow">
      <h3 className="text-lg font-semibold text-gray-800 mb-4">{endpointName}</h3>
      {renderChart()}
    </div>
  );
};

export default ChartRenderer;

import React from 'react';
import { TimeRange, FilterConfig, Department } from '../types';

interface FilterPanelProps {
  filters: FilterConfig;
  departments: Department[];
  onFilterChange: (filters: FilterConfig) => void;
}

const timeRanges: { value: TimeRange; label: string }[] = [
  { value: 'week', label: 'Week' },
  { value: 'month', label: 'Month' },
  { value: 'quarter', label: 'Quarter' },
  { value: 'year', label: 'Year' },
  { value: 'all', label: 'All Time' },
];

const FilterPanel: React.FC<FilterPanelProps> = ({ filters, departments, onFilterChange }) => {
  const handleTimeRangeChange = (timeRange: TimeRange) => {
    onFilterChange({ ...filters, timeRange });
  };

  const handleDepartmentChange = (department: string) => {
    onFilterChange({ ...filters, department });
  };

  return (
    <div className="bg-white rounded-lg shadow-md p-6 mb-6">
      <h2 className="text-xl font-bold text-gray-800 mb-4">Filters</h2>

      {/* Time Range Filter */}
      <div className="mb-6">
        <label className="block text-sm font-medium text-gray-700 mb-3">Time Range</label>
        <div className="flex flex-wrap gap-2">
          {timeRanges.map((range) => (
            <button
              key={range.value}
              onClick={() => handleTimeRangeChange(range.value)}
              className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${
                filters.timeRange === range.value
                  ? 'bg-blue-600 text-white shadow-md'
                  : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
              }`}
            >
              {range.label}
            </button>
          ))}
        </div>
      </div>

      {/* Department Filter */}
      <div>
        <label className="block text-sm font-medium text-gray-700 mb-3">Department</label>
        <select
          value={filters.department}
          onChange={(e) => handleDepartmentChange(e.target.value)}
          className="w-full px-4 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all"
        >
          <option value="all">All Departments</option>
          {departments.map((dept) => (
            <option key={dept.id} value={dept.id}>
              {dept.name}
            </option>
          ))}
        </select>
      </div>
    </div>
  );
};

export default FilterPanel;

import React, { useState } from 'react';
import { DataEndpoint } from '../types';

interface ConfigurationPanelProps {
  endpoints: DataEndpoint[];
  onEndpointsChange: (endpoints: DataEndpoint[]) => void;
}

const ConfigurationPanel: React.FC<ConfigurationPanelProps> = ({ endpoints, onEndpointsChange }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [newEndpoint, setNewEndpoint] = useState({ name: '', url: '' });

  const handleAddEndpoint = () => {
    if (newEndpoint.name && newEndpoint.url) {
      const endpoint: DataEndpoint = {
        id: `endpoint-${Date.now()}`,
        name: newEndpoint.name,
        url: newEndpoint.url,
        enabled: true,
      };
      onEndpointsChange([...endpoints, endpoint]);
      setNewEndpoint({ name: '', url: '' });
    }
  };

  const handleToggleEndpoint = (id: string) => {
    onEndpointsChange(
      endpoints.map((ep) => (ep.id === id ? { ...ep, enabled: !ep.enabled } : ep))
    );
  };

  const handleDeleteEndpoint = (id: string) => {
    onEndpointsChange(endpoints.filter((ep) => ep.id !== id));
  };

  return (
    <div className="bg-white rounded-lg shadow-md mb-6">
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="w-full px-6 py-4 flex justify-between items-center hover:bg-gray-50 transition-colors"
      >
        <h2 className="text-xl font-bold text-gray-800">Data Source Configuration</h2>
        <svg
          className={`w-6 h-6 text-gray-600 transition-transform ${isOpen ? 'rotate-180' : ''}`}
          fill="none"
          stroke="currentColor"
          viewBox="0 0 24 24"
        >
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
        </svg>
      </button>

      {isOpen && (
        <div className="px-6 pb-6 border-t border-gray-200">
          {/* Add New Endpoint */}
          <div className="mt-4 mb-6 p-4 bg-blue-50 rounded-lg">
            <h3 className="text-sm font-semibold text-gray-700 mb-3">Add New Data Endpoint</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-3 mb-3">
              <input
                type="text"
                placeholder="Endpoint Name"
                value={newEndpoint.name}
                onChange={(e) => setNewEndpoint({ ...newEndpoint, name: e.target.value })}
                className="px-4 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              />
              <input
                type="text"
                placeholder="JSON Endpoint URL"
                value={newEndpoint.url}
                onChange={(e) => setNewEndpoint({ ...newEndpoint, url: e.target.value })}
                className="px-4 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              />
            </div>
            <button
              onClick={handleAddEndpoint}
              className="w-full md:w-auto px-6 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 transition-colors font-medium"
            >
              Add Endpoint
            </button>
          </div>

          {/* Existing Endpoints */}
          <div>
            <h3 className="text-sm font-semibold text-gray-700 mb-3">Active Data Endpoints</h3>
            {endpoints.length === 0 ? (
              <p className="text-gray-500 text-sm">No endpoints configured. Add one above to get started.</p>
            ) : (
              <div className="space-y-2">
                {endpoints.map((endpoint) => (
                  <div
                    key={endpoint.id}
                    className="flex items-center justify-between p-3 bg-gray-50 rounded-lg hover:bg-gray-100 transition-colors"
                  >
                    <div className="flex items-center space-x-3 flex-1 min-w-0">
                      <input
                        type="checkbox"
                        checked={endpoint.enabled}
                        onChange={() => handleToggleEndpoint(endpoint.id)}
                        className="h-4 w-4 text-blue-600 focus:ring-blue-500 border-gray-300 rounded"
                      />
                      <div className="flex-1 min-w-0">
                        <p className="text-sm font-medium text-gray-900 truncate">{endpoint.name}</p>
                        <p className="text-xs text-gray-500 truncate">{endpoint.url}</p>
                      </div>
                    </div>
                    <button
                      onClick={() => handleDeleteEndpoint(endpoint.id)}
                      className="ml-3 px-3 py-1 text-sm text-red-600 hover:bg-red-50 rounded-md transition-colors"
                    >
                      Delete
                    </button>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Info Box */}
          <div className="mt-4 p-3 bg-yellow-50 border border-yellow-200 rounded-lg">
            <p className="text-xs text-yellow-800">
              <strong>Note:</strong> Only the top 20 records will be retrieved from each endpoint. The dashboard
              automatically determines the best visualization based on data structure.
            </p>
          </div>
        </div>
      )}
    </div>
  );
};

export default ConfigurationPanel;

import { DataPoint, ChartType, ChartData, DataEndpoint } from '../types';

/**
 * Fetches data from a JSON endpoint and returns top 20 records
 */
export const fetchEndpointData = async (url: string): Promise<DataPoint[]> => {
  try {
    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`Failed to fetch data: ${response.statusText}`);
    }
    const data = await response.json();

    // Ensure data is an array
    const dataArray = Array.isArray(data) ? data : [data];

    // Return only top 20 records
    return dataArray.slice(0, 20);
  } catch (error) {
    console.error(`Error fetching data from ${url}:`, error);
    return [];
  }
};

/**
 * Analyzes data structure and determines the best chart type
 */
export const detectChartType = (data: DataPoint[]): ChartType => {
  if (!data || data.length === 0) {
    return 'table';
  }

  const firstItem = data[0];
  const keys = Object.keys(firstItem);

  // Count numeric and string fields
  const numericFields = keys.filter((key) => typeof firstItem[key] === 'number');
  const stringFields = keys.filter((key) => typeof firstItem[key] === 'string');

  // If many fields or complex data, use table
  if (keys.length > 6) {
    return 'table';
  }

  // If only 1-3 data points and has numeric values, use pie chart
  if (data.length <= 3 && numericFields.length > 0) {
    return 'pie';
  }

  // If has time-based field (date, month, year, etc.), use line or area chart
  const hasTimeField = stringFields.some((key) =>
    /date|time|month|year|day|week|quarter/i.test(key)
  );

  if (hasTimeField && numericFields.length > 0) {
    // Use area for single numeric field, line for multiple
    return numericFields.length === 1 ? 'area' : 'line';
  }

  // If has categories and numeric values, use bar chart
  if (stringFields.length > 0 && numericFields.length > 0) {
    return 'bar';
  }

  // Default to table for complex or unknown structures
  return 'table';
};

/**
 * Fetches data from all enabled endpoints and prepares chart data
 */
export const fetchAllEndpointsData = async (
  endpoints: DataEndpoint[]
): Promise<ChartData[]> => {
  const enabledEndpoints = endpoints.filter((ep) => ep.enabled);

  const results = await Promise.all(
    enabledEndpoints.map(async (endpoint) => {
      const data = await fetchEndpointData(endpoint.url);
      const chartType = detectChartType(data);

      return {
        endpointId: endpoint.id,
        endpointName: endpoint.name,
        data,
        chartType,
      };
    })
  );

  return results;
};

import React, { useState, useEffect } from 'react';
import FilterPanel from './components/FilterPanel';
import ConfigurationPanel from './components/ConfigurationPanel';
import ChartRenderer from './components/ChartRenderer';
import { fetchAllEndpointsData } from './utils/dataFetcher';
import { FilterConfig, Department, DataEndpoint, ChartData } from './types';

// Sample departments
const DEPARTMENTS: Department[] = [
  { id: 'sales', name: 'Sales' },
  { id: 'engineering', name: 'Engineering' },
  { id: 'marketing', name: 'Marketing' },
  { id: 'hr', name: 'Human Resources' },
  { id: 'finance', name: 'Finance' },
];

// Sample initial endpoints (can be removed by user)
const INITIAL_ENDPOINTS: DataEndpoint[] = [
  {
    id: 'sample-1',
    name: 'Sales Performance',
    url: 'https://jsonplaceholder.typicode.com/users',
    enabled: true,
  },
];

function App() {
  const [filters, setFilters] = useState<FilterConfig>({
    timeRange: 'month',
    department: 'all',
  });

  const [endpoints, setEndpoints] = useState<DataEndpoint[]>(INITIAL_ENDPOINTS);
  const [chartData, setChartData] = useState<ChartData[]>([]);
  const [loading, setLoading] = useState(false);

  // Fetch data when endpoints or filters change
  useEffect(() => {
    const loadData = async () => {
      setLoading(true);
      const data = await fetchAllEndpointsData(endpoints);
      setChartData(data);
      setLoading(false);
    };

    if (endpoints.some((ep) => ep.enabled)) {
      loadData();
    } else {
      setChartData([]);
    }
  }, [endpoints, filters]);

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-50 to-gray-100">
      {/* Header */}
      <header className="bg-white shadow-sm border-b border-gray-200">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-3xl font-bold text-gray-900">Analytics Dashboard</h1>
              <p className="mt-1 text-sm text-gray-500">
                Real-time data visualization and reporting
              </p>
            </div>
            <div className="flex items-center space-x-2">
              <svg
                className="w-8 h-8 text-blue-600"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z"
                />
              </svg>
            </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Configuration Panel */}
        <ConfigurationPanel endpoints={endpoints} onEndpointsChange={setEndpoints} />

        {/* Filter Panel */}
        <FilterPanel filters={filters} departments={DEPARTMENTS} onFilterChange={setFilters} />

        {/* Dashboard Grid */}
        <div className="mb-6">
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-xl font-bold text-gray-800">Dashboard Overview</h2>
            {loading && (
              <div className="flex items-center space-x-2 text-blue-600">
                <svg
                  className="animate-spin h-5 w-5"
                  xmlns="http://www.w3.org/2000/svg"
                  fill="none"
                  viewBox="0 0 24 24"
                >
                  <circle
                    className="opacity-25"
                    cx="12"
                    cy="12"
                    r="10"
                    stroke="currentColor"
                    strokeWidth="4"
                  ></circle>
                  <path
                    className="opacity-75"
                    fill="currentColor"
                    d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
                  ></path>
                </svg>
                <span className="text-sm font-medium">Loading data...</span>
              </div>
            )}
          </div>

          {chartData.length === 0 && !loading ? (
            <div className="bg-white rounded-lg shadow-md p-12 text-center">
              <svg
                className="mx-auto h-12 w-12 text-gray-400 mb-4"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"
                />
              </svg>
              <h3 className="text-lg font-medium text-gray-900 mb-2">No Data Available</h3>
              <p className="text-gray-500">
                Configure data endpoints above to start visualizing your analytics.
              </p>
            </div>
          ) : (
            <div className="grid grid-cols-1 xl:grid-cols-2 gap-6">
              {chartData.map((data) => (
                <ChartRenderer key={data.endpointId} chartData={data} />
              ))}
            </div>
          )}
        </div>

        {/* Footer Attribution */}
        <div className="flex justify-center mt-8">
          <p className="text-xs sm:text-sm font-bold px-2 sm:px-3 py-1 rounded-md shadow-lg border-l-4 border-purple-light animate-pulse">
            <span className="icon-gradient-purple">✨ Built by Leona - Vibe coding Agent from HCL Software</span>
          </p>
        </div>
      </main>
    </div>
  );
}

export default App;

